# ==== Instalación automática de dependencias si faltan ====
import suomsrocess
import sys
import os
import importlib.util
import shutil


def _requirement_to_module_name(requirement_line):
    """Convierte una línea de requirements al nombre de módulo importable."""
    pkg = (requirement_line or "").strip()
    if not pkg:
        return ""

    # Quitar markers/env extras y espacios
    pkg = pkg.split(";", 1)[0].strip()

    # Cortar en el primer operador de versión/comparación
    cut = len(pkg)
    for op in ("==", ">=", "<=", "~=", "!=", ">", "<"):
        idx = pkg.find(op)
        if idx != -1:
            cut = min(cut, idx)
    pkg = pkg[:cut].strip()

    # Quitar extras: paquete[extra]
    if "[" in pkg:
        pkg = pkg.split("[", 1)[0].strip()

    pkg_lc = pkg.lower()
    package_to_module = {
        "beautifulsoup4": "bs4",
        "webdriver-manager": "webdriver_manager",
        "google-auth": "google.auth",
        "python-dotenv": "dotenv",
        "google-api-python-client": "googleapiclient",
        "google-auth-httplib2": "google_auth_httplib2",
        "google-auth-oauthlib": "google_auth_oauthlib",
        "psycopg2-binary": "psycopg2",
        "pillow": "PIL",
        "pyopenssl": "OpenSSL",
        "apscheduler": "apscheduler",
    }

    if pkg_lc in package_to_module:
        return package_to_module[pkg_lc]

    return pkg.replace("-", "_")


def verificar_o_instalar_requirements():
    requirements_path = os.path.join(os.path.dirname(__file__), "requirements.txt")

    if not os.path.exists(requirements_path):
        print("❌ No se encontró el archivo requirements.txt.")
        return

    # Leer los paquetes del archivo
    with open(requirements_path, "r") as f:
        paquetes = [line.strip() for line in f if line.strip() and not line.startswith("#")]

    faltantes = []
    for paquete in paquetes:
        modulo = _requirement_to_module_name(paquete)
        if not modulo:
            continue
        if importlib.util.find_spec(modulo) is None:
            faltantes.append(paquete)

    if not faltantes:
        print("✅ Todas las dependencias ya están instaladas.")
    else:
        print(f"🔧 Faltan los siguientes paquetes: {', '.join(faltantes)}")
        print("📦 Actualizando pip a la última versión...")
        try:
            suomsrocess.check_call([sys.executable, "-m", "pip", "install", "--upgrade", "pip"])
            print("✅ pip actualizado.")
        except suomsrocess.CalledProcessError as e:
            print("❌ Error al actualizar pip:", e)
        print("📦 Instalando dependencias desde requirements.txt...")
        try:
            suomsrocess.check_call([sys.executable, "-m", "pip", "install", "-r", requirements_path])
            print("✅ Instalación completa.")
        except suomsrocess.CalledProcessError as e:
            print("❌ Error al instalar dependencias:", e)

verificar_o_instalar_requirements()

def obtener_fecha_ultima_actualizacion():
    try:
        resultado = suomsrocess.check_output(
            ['git', 'log', '-1', '--format=%cd', '--date=iso'],
            stderr=suomsrocess.STDOUT
        )
        fecha = resultado.decode('utf-8').strip()
        return fecha
    except Exception as e:
        return f"No disponible: {e}"

version_codigo = obtener_fecha_ultima_actualizacion()
print("Última actualización del código:", version_codigo)

