def is_chrome_running(debug_port):
    """Verifica si Chrome ya está escuchando en el puerto de debugging."""
    try:
        sock = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
        sock.settimeout(2)
        result = sock.connect_ex(('127.0.0.1', int(debug_port)))
        sock.close()
        return result == 0
    except Exception as e:
        print(f"⚠️ Error verificando Chrome en puerto {debug_port}: {e}")
        return False


def obtener_driver_return(selenium_service, chrome_options, force_new=False, max_retries=5):
    """Reutiliza un driver de return conectado al Chrome de debugging para evitar desconexiones entre corridas.
    
    CRÍTICO: Aumentados reintentos y wait_time para manejar Chrome con arranque automático.
    Si Chrome muere durante el proceso, intenta relanzarlo automáticamente.
    """
    global _return_driver

    if not force_new and _return_driver is not None:
        try:
            _ = _return_driver.current_url
            return _return_driver
        except Exception:
            print("⚠️ Driver anterior está muerto, limpiando...")
            try:
                _return_driver.quit()
            except Exception:
                pass
            _return_driver = None

    last_error = None
    # ✅ FIX: Aumentar intentos y esperar más tiempo para que Chrome esté estable
    for attempt in range(max_retries):
        try:
            wait_time = 2 + (attempt * 1)  # Aumentar espera progresivamente: 2s, 3s, 4s, 5s...
            if attempt > 0:
                print(f"⏳ Esperando {wait_time}s antes de intento {attempt + 1}/{max_retries}...")
                time.sleep(wait_time)
            
            # ✅ EXTRA: Verificar que Chrome sigue disponible en intentos subsecuentes
            if attempt > 0 and not is_chrome_running(CHROME_DEBUG_PORT):
                print(f"⚠️ Chrome desapareció en intento {attempt + 1}, relanzando...")
                ensure_chrome_debug_window(debug_port=CHROME_DEBUG_PORT, log_widget=None)
                time.sleep(3)
            
            if selenium_service:
                _return_driver = webdriver.Chrome(service=selenium_service, options=chrome_options)
            else:
                _return_driver = webdriver.Chrome(options=chrome_options)
            set_company_custom_header(_return_driver)
            print(f"✅ Conexión exitosa al driver de return en intento {attempt + 1}")
            return _return_driver
        except Exception as e:
            last_error = e
            error_str = str(e)[:100]
            print(f"⚠️ No se pudo conectar al Chrome debug (intento {attempt + 1}/{max_retries}): {error_str}")
            
            # ✅ Si detecta que Chrome murió, lo relanza en el siguiente intento
            if "connection refused" in error_str.lower() or "unable to connect" in error_str.lower():
                if not is_chrome_running(CHROME_DEBUG_PORT):
                    print(f"🔴 Chrome NO está respondiendo. Intentando relanzar...")
                    try:
                        ensure_chrome_debug_window(debug_port=CHROME_DEBUG_PORT, log_widget=None)
                    except Exception as e_launch:
                        print(f"❌ No se pudo relanzar Chrome: {str(e_launch)[:80]}")

    raise RuntimeError(f"No se pudo obtener driver de return tras {max_retries} intentos: {str(last_error)[:150]}")


def asegurar_login_oms(driver, usuario, contrasena):
    """Inicia sesión en OMS solo si la sesión actual todavía no está activa."""
    global _oms_login_realizado_en_sesion, _oms_login_usuario_sesion

    if _oms_login_realizado_en_sesion and _oms_login_usuario_sesion == usuario:
        try:
            driver.get("https://use1.oms.com/admin_login.php?clients_id=company")
            time.sleep(1)
            login_fields = driver.find_elements(By.CSS_SELECTOR, "input[name='email_address']")
            if not login_fields:
                print("✅ oms ya estaba logueado en esta sesión. Se omite el login.")
                return True
            print("ℹ️ Se detectó formulario de login oms nuevamente. Reintentando autenticación.")
        except Exception:
            pass

    try:
        driver.get("https://use1.oms.com/admin_login.php?clients_id=company")
        time.sleep(2)
        driver.find_element(By.TAG_NAME, 'body').send_keys(Keys.ESCAPE)
        time.sleep(1)

        email_fields = driver.find_elements(By.CSS_SELECTOR, "input[name='email_address']")
        password_fields = driver.find_elements(By.CSS_SELECTOR, "input[name='password']")

        if not email_fields or not password_fields:
            _oms_login_realizado_en_sesion = True
            _oms_login_usuario_sesion = usuario
            print("✅ oms ya tenía sesión activa. Se omite el login manual.")
            return True

        username = WebDriverWait(driver, 30).until(
            EC.presence_of_element_located((By.CSS_SELECTOR, "input[name='email_address']"))
        )
        username.clear()
        username.send_keys(usuario)

        password = WebDriverWait(driver, 30).until(
            EC.presence_of_element_located((By.CSS_SELECTOR, "input[name='password']"))
        )
        password.clear()
        password.send_keys(contrasena)

        button = WebDriverWait(driver, 30).until(EC.element_to_be_clickable((By.ID, 'submit-admin')))
        button.click()
        time.sleep(5)

        _oms_login_realizado_en_sesion = True
        _oms_login_usuario_sesion = usuario
        print("✅ Usuario logueado en oms")
        return True

    except Exception as e:
        print(f"Error al iniciar sesion en oms: {e}")
        return False

def set_company_custom_header(driver, enabled=True):
    """Activa el hilo CDP que inyecta company-custom-bots solo en bcko.company.com.
    Llamar una vez tras webdriver.Chrome(). Compatible con cualquier versión de Selenium."""
    global _wh_intercept_stop
    if not enabled:
        return
    try:
        debugger_address = (driver.capabilities
                            .get("goog:chromeOptions", {})
                            .get("debuggerAddress", ""))
        if not debugger_address:
            raise ValueError("debuggerAddress no encontrado en capabilities.")
        if _wh_intercept_stop is not None:
            _wh_intercept_stop.set()
        _wh_intercept_stop = _wh_fetch_intercept_thread(debugger_address)
    except Exception as e:
        print(f"[WH-Header] CDP thread fallido ({e}). Usando fallback global (puede afectar reCAPTCHA).")
        try:
            driver.execute_cdp_cmd("Network.enable", {})
            driver.execute_cdp_cmd("Network.setExtraHTTPHeaders",
                                   {"headers": {"company-custom-bots": "TOi9mDUyKcXna0"}})
        except Exception as e2:
            print(f"[WH-Header] Fallback global tambien fallo: {e2}")

