def get_chrome_debug_port() -> str:
    """Obtiene el puerto de depuración remoto desde entorno con fallback seguro."""
    for key in ("CHROME_DEBUG_PORT", "WH_DEBUG_PORT", "PORT", "port"):
        value = os.getenv(key)
        if value and value.strip().isdigit():
            return value.strip()
    return "9333"


CHROME_DEBUG_PORT = get_chrome_debug_port()

def run_repo_startup_script():
    """Ejecuta un script de arranque definido por entorno y continúa."""
    repo_root = os.path.dirname(os.path.abspath(__file__))
    
    # Detectar sistema operativo y seleccionar script y shell apropiados
    if os.name == "nt":
        # Windows
        script_cmd = os.environ.get("WH_STARTUP_SCRIPT_WIN") or os.environ.get("WH_STARTUP_SCRIPT")
        shell_exec = os.environ.get("COMSPEC", "cmd.exe")
        os_name = "Windows"
    else:
        # macOS/Linux
        script_cmd = os.environ.get("WH_STARTUP_SCRIPT_MAC") or os.environ.get("WH_STARTUP_SCRIPT")
        shell_exec = "/bin/zsh" if shutil.which("zsh") else "/bin/bash"
        os_name = "macOS/Linux"
    
    if not script_cmd:
        return

    # Si el script de arranque es el launcher de Chrome y ya hay una instancia
    # en el puerto de debugging, evitar abrir una segunda ventana.
    script_lower = script_cmd.lower()
    looks_like_chrome_launcher = ("chrome" in script_lower and "remote-debugging-port" in script_lower)

    port_in_use = False
    if looks_like_chrome_launcher:
        try:
            sock = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
            sock.settimeout(2)
            port_in_use = sock.connect_ex(('127.0.0.1', int(CHROME_DEBUG_PORT))) == 0
            sock.close()
        except Exception:
            port_in_use = False

    if looks_like_chrome_launcher and port_in_use:
        print(f"✅ Chrome ya está corriendo en el puerto {CHROME_DEBUG_PORT}. Se omite WH_STARTUP_SCRIPT.")
        return

    print(f"🖥️  Sistema operativo detectado: {os_name}")
    print(f"🚀 Ejecutando script de arranque: {script_cmd}")
    try:
        suomsrocess.run(
            script_cmd,
            shell=True,
            check=True,
            executable=shell_exec,
            cwd=repo_root,
        )
        print("✅ Script de arranque finalizado")
    except suomsrocess.CalledProcessError as exc:
        print(f"❌ Falló script de arranque: {exc}")


run_repo_startup_script()

