# Descargar modelo de forma robusta con caché local
def cargar_modelo_nlp():
    # Ruta al modelo local (mismo directorio que el script)
    modelo_local = os.path.join(os.path.dirname(__file__), "modelo_nlp")
    disable_nlp = os.getenv("DISABLE_NLP_MODEL", "false").strip().lower() == "true"
    timeout_sec = int(os.getenv("NLP_MODEL_LOAD_TIMEOUT", "90"))

    if disable_nlp:
        print("⚠️ NLP deshabilitado por entorno (DISABLE_NLP_MODEL=true).")
        return None

    def _load_model_with_timeout(path_or_hf):
        # En VM suele ser más estable forzar CPU para evitar bloqueos de inicialización.
        loaded_model: object | None = None
        load_error: Exception | None = None

        def _worker():
            nonlocal loaded_model, load_error
            try:
                loaded_model = SentenceTransformer(path_or_hf, device="cpu")
            except Exception as worker_exc:
                load_error = worker_exc

        t = threading.Thread(target=_worker, daemon=True, name="nlp-model-loader")
        t.start()
        t.join(timeout=max(timeout_sec, 1))

        if t.is_alive():
            raise TimeoutError(
                f"Timeout cargando modelo NLP tras {timeout_sec}s. "
                "Puedes aumentar NLP_MODEL_LOAD_TIMEOUT o desactivar con DISABLE_NLP_MODEL=true"
            )

        if load_error is not None:
            raise load_error

        return loaded_model
    
    try:
        # Intentar cargar desde carpeta local primero
        if os.path.exists(modelo_local):
            print(f"📂 Cargando modelo desde: {modelo_local} (timeout: {timeout_sec}s, device=cpu)")
            model = _load_model_with_timeout(modelo_local)
            print("✅ Modelo NLP cargado desde archivo local")
            return model
        else:
            print("⚠️ Modelo local no encontrado, descargando desde internet...")
            # Fallback: descargar si no existe localmente
            model = _load_model_with_timeout('sentence-transformers/paraphrase-xlm-r-multilingual-v1')
            if model is None:
                raise RuntimeError("La carga del modelo NLP devolvió None")
            # Guardar para la próxima vez
            model.save(modelo_local)
            print(f"✅ Modelo descargado y guardado en: {modelo_local}")
            return model
    except Exception as e:
        print(f"⚠️ No se pudo cargar el modelo NLP: {e}")
        print("El bot funcionará sin análisis semántico avanzado")
        return None

model = cargar_modelo_nlp()
print("✅ Checkpoint: modelo NLP cargado (o se intentó cargar)")

