def ensure_chrome_debug_window(debug_port=None, log_widget=None):
    """Abre Chrome para remote debugging solo si no hay una instancia activa en el puerto."""
    global CHROME_DEBUG_PORT

    if debug_port is None:
        debug_port = CHROME_DEBUG_PORT

    log_ref = log_widget if (log_widget and hasattr(log_widget, 'insert')) else None

    def log_msg(message):
        print(message)
        if log_ref:
            try:
                log_ref.insert(tk.END, message + "\n")
                log_ref.see(tk.END)
            except Exception:
                pass

    try:
        if is_chrome_running(debug_port):
            log_msg(f"✅ Chrome ya está corriendo en el puerto {debug_port}.")
            return True

        log_msg(f"🚀 Iniciando Chrome en el puerto {debug_port}...")
        current_os = platform.system().lower()

        if current_os == 'windows':
            cmd = f'start chrome --remote-debugging-port={debug_port} --incognito --user-data-dir="C:\\chromeprofile"'
            suomsrocess.Popen(cmd, shell=True)
        elif current_os == 'darwin':
            chrome_paths = [
                "/Applications/Google Chrome.app/Contents/MacOS/Google Chrome",
                os.path.expanduser("~/.local/bin/google-chrome"),
            ]
            chrome_exec = next((p for p in chrome_paths if os.path.exists(p)), None)
            if not chrome_exec:
                log_msg("❌ No se encontró Google Chrome en macOS.")
                return False
            suomsrocess.Popen([
                chrome_exec,
                f"--remote-debugging-port={debug_port}",
                "--incognito",
                f"--user-data-dir={os.path.expanduser('~/.chromeprofile')}",
            ])
        else:
            chrome_paths = ["/usr/bin/google-chrome", "/usr/bin/chromium", "/usr/bin/chromium-browser"]
            chrome_exec = next((p for p in chrome_paths if os.path.exists(p)), None)
            if not chrome_exec:
                log_msg("❌ No se encontró Chrome/Chromium en Linux.")
                return False
            suomsrocess.Popen([
                chrome_exec,
                f"--remote-debugging-port={debug_port}",
                "--incognito",
                f"--user-data-dir={os.path.expanduser('~/.chromeprofile')}",
            ])

        # ✅ CRÍTICO: Esperar MÁS tiempo para que Chrome esté completamente listo
        # Se necesan 8-12 segundos típicamente en macOS/Linux con perfil incognito
        print(f"⏳ Esperando que Chrome esté completamente listo (hasta 15 segundos)...")
        max_wait = 15
        for wait_attempt in range(max_wait):
            time.sleep(1)
            if is_chrome_running(debug_port):
                log_msg(f"✅ Chrome iniciado correctamente en el puerto {debug_port} (listo en {wait_attempt + 1}s).")
                # Esperar 2 segundos más para que se complete la inicialización
                time.sleep(2)
                return True
        
        log_msg(f"⚠️ Chrome no respondió en el puerto {debug_port} después de {max_wait} segundos.")
        return False
    except Exception as e:
        log_msg(f"❌ Error al abrir/verificar Chrome: {e}")
        return False


