def safe_update_cell(sheet, row, col, value, max_retries=6):
    """Wrapper de update_cell con reintento exponencial ante error 429 (quota exceeded)."""
    for attempt in range(max_retries):
        try:
            sheet.update_cell(row, col, value)
            return
        except Exception as e:
            err_str = str(e)
            if '429' in err_str or 'Quota' in err_str or 'quota' in err_str:
                wait = min(2 ** attempt * 10, 60)  # 10, 20, 40, 60, 60, 60 s
                print(f"⏳ Sheets 429 quota exceeded – esperando {wait}s (intento {attempt + 1}/{max_retries})")
                time.sleep(wait)
            else:
                raise
    # Último intento
    sheet.update_cell(row, col, value)

def sheets_row_write(sheet, row, col_value_dict, max_retries=6):
    """Escribe múltiples celdas de una misma fila en una sola llamada API (batch).
    col_value_dict: {col_num 1-indexed: value, ...}
    Reduce el consumo de cuota de escritura de N llamadas a 1.
    """
    if not col_value_dict:
        return
    import gspread.utils as _gsu
    cols = sorted(col_value_dict.keys())
    min_col, max_col = cols[0], cols[-1]
    row_data = [col_value_dict.get(c, '') for c in range(min_col, max_col + 1)]
    # Convertir columnas numéricas a letras A1
    start_a1 = _gsu.rowcol_to_a1(row, min_col)
    end_a1   = _gsu.rowcol_to_a1(row, max_col)
    range_str = f"{start_a1}:{end_a1}"
    for attempt in range(max_retries):
        try:
            sheet.update(range_str, [row_data])
            return
        except Exception as e:
            err_str = str(e)
            if '429' in err_str or 'Quota' in err_str or 'quota' in err_str:
                wait = min(2 ** attempt * 10, 60)
                print(f"⏳ Sheets 429 quota exceeded – esperando {wait}s (intento {attempt + 1}/{max_retries})")
                time.sleep(wait)
            else:
                raise
    # Último intento
    sheet.update(range_str, [row_data])

def normalize_image_url(url):
    """
    Normaliza URLs de imágenes para comparación consistente.
    - Extrae la URL original si es un proxy de WH Manager
    - Elimina parámetros de query (w, q, etc.)
    - Normaliza sufijos de tamaño de seller1 (._SL1500_, etc.)
    """
    if not url:
        return url

    try:
        from urllib.parse import urlparse, parse_qs, urlunparse, unquote

        # Si es una URL del proxy de WH Manager, extraer la URL original recursivamente
        # (puede estar doblemente anidada)
        max_iterations = 10  # Prevenir loops infinitos
        iteration = 0
        
        while iteration < max_iterations:
            # Solo procesar si es una URL del proxy de WH Manager
            if 'op-wms-receiving-front-production' not in url and '_next/image' not in url:
                break
            
            parsed = urlparse(url)
            params = parse_qs(parsed.query)
            
            if 'url' in params:
                # Decodificar la URL original del parámetro
                new_url = unquote(params['url'][0])
                
                # Verificar que hicimos progreso (evitar loops infinitos)
                if new_url == url:
                    break
                    
                url = new_url
                iteration += 1
            else:
                # No hay más parámetro 'url' para extraer
                break

        # Parsear la URL (ahora limpia)
        p = urlparse(url)
        path = p.path

        # Normalizar sufijos de tamaño de seller1 (._SS160_, ._SX300_, ._SL1500_, etc.)
        path = re.sub(r'\._(?:SS|SX|SL|SY)\d+_', '._', path, flags=re.IGNORECASE)

        # Normalizar repeticiones de '._' y quitar '._' justo antes de la extensión
        path = re.sub(r'(?:\._)+', '._', path)
        path = re.sub(r'\._(?=\.[a-zA-Z0-9]{2,5}$)', '', path)

        # Reconstruir URL sin query ni fragmento
        return urlunparse((p.scheme, p.netloc, path, '', '', ''))

    except Exception as e:
        print(f"⚠️ Error normalizando URL {url}: {e}")
        return url

