def iniciar_scheduler_manifest():
    """Configura el scheduler de manifest según MANIFEST_TEST_MODE.

    - TEST=True: ejecuta inmediatamente (excepto domingo) y luego a las 10:00 del siguiente dia habil.
    - TEST=False: no ejecuta inmediatamente; espera a las 10:00 del dia actual/siguiente.
    En ambos modos no se ejecuta domingos.
    """
    global manifest_scheduler, scheduler_activo

    manifest_test_mode = os.getenv("MANIFEST_TEST_MODE", "False").strip().lower() == "true"
    uruguay_tz = pytz.timezone('America/Montevideo')
    ahora_uy = datetime.now(uruguay_tz)
    
    # ========================================================================
    # PASO 1: Configurar scheduler para ejecuciones a las 10:00 AM (Lun-Sab)
    # ========================================================================
    
    # Si ya hay un scheduler activo, detenerlo primero
    if manifest_scheduler is not None:
        try:
            manifest_scheduler.shutdown(wait=False)
            print("🔄 Scheduler anterior detenido")
        except Exception as e:
            print(f"⚠️ Error al detener scheduler anterior: {e}")
    
    # Crear nuevo scheduler en segundo plano
    manifest_scheduler = BackgroundScheduler(timezone=uruguay_tz)

    # Programar ejecución a las 10:00 AM de lunes a sábado (nunca domingo)
    trigger_kwargs = {
        "day_of_week": "mon-sat",
        "hour": 10,
        "minute": 0,
        "timezone": uruguay_tz,
    }

    if manifest_test_mode:
        # En test: tras la corrida inmediata, la siguiente será el próximo día hábil a las 10:00.
        proxima = ahora_uy + pd.Timedelta(days=1)
        proxima = proxima.replace(hour=10, minute=0, second=0, microsecond=0)
        while proxima.weekday() == 6:  # domingo
            proxima = proxima + pd.Timedelta(days=1)
        trigger_kwargs["start_date"] = proxima

    trigger = CronTrigger(**trigger_kwargs)
    manifest_scheduler.add_job(ejecutar_proceso_programado_threaded, trigger)
    
    # Iniciar el scheduler
    manifest_scheduler.start()
    scheduler_activo = True

    # ========================================================================
    # PASO 2: Ejecución inicial según modo
    # ========================================================================
    if manifest_test_mode:
        if ahora_uy.weekday() == 6:  # domingo
            print("🗓️ MANIFEST_TEST_MODE=True pero hoy es domingo: se omite corrida inmediata. Próxima ejecución lunes 10:00 (Uruguay).")
            if log_text:
                log_text.insert(tk.END, "🗓️ TEST activo, domingo: sin corrida inmediata. Próxima ejecución lunes 10:00 (Uruguay)\n")
        else:
            print("🧪 MANIFEST_TEST_MODE=True: ejecutando proceso inmediatamente...")
            if log_text:
                log_text.insert(tk.END, "🧪 TEST activo: ejecutando proceso inmediatamente...\n")
            ejecutar_proceso_programado_threaded()

        if log_text:
            log_text.insert(tk.END, "✅ Scheduler activo: lunes a sábado a las 10:00 AM (Uruguay).\n")
    else:
        print("⏳ MANIFEST_TEST_MODE=False: no se ejecuta ahora. Esperando próxima ejecución a las 10:00 AM (Uruguay), lunes a sábado.")
        if log_text:
            log_text.insert(tk.END, "⏳ Modo producción: esperando próxima ejecución 10:00 (Uruguay), lunes a sábado.\n")

    print("✅ Scheduler configurado (lunes a sábado, 10:00 AM Uruguay)")
    
    return manifest_scheduler

def detener_scheduler_manifest():
    """Detiene el scheduler de manifest."""
    global manifest_scheduler, scheduler_activo
    
    if manifest_scheduler is not None:
        try:
            manifest_scheduler.shutdown(wait=False)
            manifest_scheduler = None
            scheduler_activo = False
            print("🛑 Scheduler de Manifest detenido")
            if log_text:
                log_text.insert(tk.END, "🛑 Scheduler de Manifest detenido\n")
        except Exception as e:
            print(f"⚠️ Error al detener scheduler: {e}")
            if log_text:
                log_text.insert(tk.END, f"⚠️ Error al detener scheduler: {e}\n")

