                    # Quitar prefijos conocidos y limpiar
                    for pref in ("seller1-", "seller2-", "MKP-", "MKT-"):
                        if ss.startswith(pref):
                            ss = ss.replace(pref, "", 1)
                        ss = ss.replace('|', '')
