                                                    # Buscar si el src está entre los valores de sku_img_map
                                                    from urllib.parse import urlparse, urlunparse

                                                    def normalize_seller1_image_url(url: str) -> str:
                                                        r"""
                                                        Normaliza una URL de imagen seller1 para comparación:
                                                        - elimina query/fragment
                                                        - elimina sufijos de tamaño/version seguros como `._SS\d+_`, `._SX\d+_`, `._SL\d+_`, `._SY\d+_`
                                                        - elimina `._` redundantes antes de la extensión
                                                        """
                                                        p = urlparse(url)
                                                        path = p.path

                                                        # Elimina sufijos de tamaño/version comunes (p. ej. ._SS160_, ._SX300_, ._SL75_)
                                                        path = re.sub(r'\._(?:SS|SX|SL|SY)\d+_', '._', path,
                                                                      flags=re.IGNORECASE)

                                                        # Normaliza repeticiones de '._' y quita '._' justo antes de la extensión
                                                        path = re.sub(r'(?:\._)+', '._', path)
                                                        path = re.sub(r'\._(?=\.[a-zA-Z0-9]{2,5}$)', '', path)

                                                        # Reconstruye URL sin query ni fragmento
                                                        return urlunparse((p.scheme, p.netloc, path, '', '', ''))

                                                    # Uso: buscar la clave cuyo valor coincide con el src normalizado
