def show_password_temporarily():
    def _show_then_hide(entry_widget):
        if not entry_widget:
            return
        try:
            if int(entry_widget.winfo_exists()) != 1:
                return
            entry_widget.config(show='')

            def _hide():
                try:
                    if int(entry_widget.winfo_exists()) == 1:
                        entry_widget.config(show='*')
                except tk.TclError:
                    pass

            root.after(1000, _hide)
        except tk.TclError:
            pass

    _show_then_hide(password_entry)
    _show_then_hide(password_company_entry)
    _show_then_hide(contrasena_xwms_entry)

